CREATE TABLE countries (
    id UUID PRIMARY KEY,
    code VARCHAR(2) NOT NULL UNIQUE,
    name VARCHAR(120) NOT NULL UNIQUE,
    active BOOLEAN NOT NULL DEFAULT TRUE
);

CREATE TABLE departments (
    id UUID PRIMARY KEY,
    country_id UUID NOT NULL REFERENCES countries(id),
    name VARCHAR(120) NOT NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    CONSTRAINT uq_departments_country_name UNIQUE (country_id, name)
);

CREATE TABLE cities (
    id UUID PRIMARY KEY,
    department_id UUID NOT NULL REFERENCES departments(id),
    name VARCHAR(120) NOT NULL,
    active BOOLEAN NOT NULL DEFAULT TRUE,
    CONSTRAINT uq_cities_department_name UNIQUE (department_id, name)
);

ALTER TABLE users
    ADD COLUMN country_id UUID REFERENCES countries(id),
    ADD COLUMN department_id UUID REFERENCES departments(id),
    ADD COLUMN city_id UUID REFERENCES cities(id);

ALTER TABLE service_requests
    ADD COLUMN city_id UUID REFERENCES cities(id);

CREATE INDEX idx_departments_country ON departments(country_id, active);
CREATE INDEX idx_cities_department ON cities(department_id, active);
CREATE INDEX idx_users_city ON users(city_id);
CREATE INDEX idx_service_requests_city_status ON service_requests(city_id, status);




UPDATE users u
SET country_id = '00000000-0000-0000-0000-000000000170',
    department_id = c.department_id,
    city_id = c.id
FROM cities c
WHERE u.home_city IS NOT NULL
  AND lower(trim(u.home_city)) = lower(c.name);

UPDATE service_requests request
SET city_id = client.city_id
FROM users client
WHERE request.client_id = client.id
  AND client.city_id IS NOT NULL;
